// Base URL prefix for locally-hosted SVGs. In production this resolves to
// the deploy base (e.g. "/" or "/tags-modal/"). Override via Vite's BASE_URL.
const LOCAL_BASE = (typeof import.meta !== 'undefined' && import.meta.env?.BASE_URL) || '/';

export function iconLocalUrl(icon: IconEntry): string {
  return `${LOCAL_BASE}icons/${icon.c}/${icon.s}.svg`.replace(/\/{2,}/g, '/');
}

export function iconCdnUrl(icon: IconEntry): string {
  return `https://cdn.jsdelivr.net/gh/microsoft/fluentui-emoji@main/assets/${encodeURIComponent(icon.d)}/${icon.p}.svg`;
}

// Kept for backwards-compat: returns the preferred URL (local first).
export function iconSvgUrl(icon: IconEntry): string {
  return iconLocalUrl(icon);
}

export function iconByEmoji(emoji: string): IconEntry | undefined {
  return ICONS.find(i => i.e === emoji);
}
